glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
in vec3 a_position;
in mediump vec2 a_uv0;
out mediump vec2 v_uv0;
void main () {
  gl_Position = cc_matViewProj * vec4(a_position, 1);
  v_uv0 = a_uv0;
}

glsl3.frag:
precision highp float;
uniform sampler2D texture;
in mediump vec2 v_uv0;
uniform FragConstants {
  vec4 scolor;
  float width;
  float strength;
  float offsett;
  float time;
};
void main () {
  vec4 color = scolor * texture2D(texture, v_uv0).rgba;
  float start = tan(time/1.414);
  if(v_uv0.x < (start - offsett * v_uv0.y) &&  v_uv0.x > (start - offsett * v_uv0.y - width))
  {
    vec3 improve = strength * vec3(255, 255, 255);
    vec3 result = improve * vec3( color.r, color.g, color.b);
    gl_FragColor = vec4(result, color.a);
  }else{
    gl_FragColor = color;
  }
}

glsl1.vert:
precision highp float;
uniform mat4 cc_matViewProj;
attribute vec3 a_position;
attribute mediump vec2 a_uv0;
varying mediump vec2 v_uv0;
void main () {
  gl_Position = cc_matViewProj * vec4(a_position, 1);
  v_uv0 = a_uv0;
}

